"""Relay hook events to the dashboard HTTP server.

Used as a Claude Code command hook. Reads JSON from stdin,
POSTs it to the dashboard's HTTP server on localhost:17384.
Non-blocking — if the server is down, exits silently.
"""

import json
import sys
import urllib.request


def main():
    try:
        data = sys.stdin.read()
        if not data:
            return

        req = urllib.request.Request(
            "http://127.0.0.1:17384/hook",
            data=data.encode(),
            headers={"Content-Type": "application/json"},
            method="POST",
        )
        urllib.request.urlopen(req, timeout=2)
    except Exception:
        pass  # Non-blocking — dashboard may not be running


if __name__ == "__main__":
    main()
